head.b:skin:
/* Anime Streaming Template CSS */
:root {
  --bg-primary: #0f0f0f;
  --bg-secondary: #1a1a1a;
  --bg-tertiary: #252525;
  --text-primary: #ffffff;
  --text-secondary: #b3b3b3;
  --accent-color: #ff6b6b;
  --accent-hover: #ff5252;
  --border-color: #333;
  --success-color: #4caf50;
  --warning-color: #ff9800;
  --danger-color: #f44336;
  --font-primary: 'Inter', sans-serif;
  --font-heading: 'Poppins', sans-serif;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: var(--font-primary);
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  overflow-x: hidden;
}

/* Loading Screen */
#loading-screen {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--bg-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  transition: opacity 0.5s ease;
}

.loading-spinner {
  width: 50px;
  height: 50px;
  border: 3px solid var(--border-color);
  border-top: 3px solid var(--accent-color);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* Header */
.header {
  background: rgba(15, 15, 15, 0.95);
  backdrop-filter: blur(10px);
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  border-bottom: 1px solid var(--border-color);
}

.header-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 2rem;
  max-width: 1200px;
  margin: 0 auto;
}

.logo {
  font-family: var(--font-heading);
  font-size: 1.8rem;
  font-weight: 700;
  color: var(--accent-color);
  text-decoration: none;
}

.nav-menu {
  display: flex;
  list-style: none;
  gap: 2rem;
}

.nav-menu a {
  color: var(--text-primary);
  text-decoration: none;
  font-weight: 500;
  transition: color 0.3s ease;
  position: relative;
}

.nav-menu a:hover {
  color: var(--accent-color);
}

.nav-menu a::after {
  content: '';
  position: absolute;
  bottom: -5px;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--accent-color);
  transition: width 0.3s ease;
}

.nav-menu a:hover::after {
  width: 100%;
}

/* Search Bar */
.search-container {
  position: relative;
  display: flex;
  align-items: center;
}

.search-input {
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  border-radius: 25px;
  padding: 0.7rem 1.2rem;
  color: var(--text-primary);
  width: 250px;
  transition: all 0.3s ease;
}

.search-input:focus {
  outline: none;
  border-color: var(--accent-color);
  width: 300px;
}

.search-btn {
  position: absolute;
  right: 10px;
  background: none;
  border: none;
  color: var(--text-secondary);
  cursor: pointer;
  font-size: 1.1rem;
}

/* Mobile Menu Toggle */
.mobile-toggle {
  display: none;
  flex-direction: column;
  cursor: pointer;
}

.mobile-toggle span {
  width: 25px;
  height: 3px;
  background: var(--text-primary);
  margin: 3px 0;
  transition: 0.3s;
}

/* Main Content */
.main-content {
  margin-top: 80px;
  min-height: calc(100vh - 80px);
}

/* Hero Section */
.hero-section {
  position: relative;
  height: 500px;
  background: linear-gradient(45deg, var(--bg-secondary), var(--bg-tertiary));
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.hero-content {
  text-align: center;
  z-index: 2;
}

.hero-title {
  font-family: var(--font-heading);
  font-size: 3.5rem;
  font-weight: 700;
  margin-bottom: 1rem;
  background: linear-gradient(45deg, var(--accent-color), #ff8e8e);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.hero-subtitle {
  font-size: 1.2rem;
  color: var(--text-secondary);
  margin-bottom: 2rem;
}

.cta-button {
  background: var(--accent-color);
  color: white;
  border: none;
  padding: 1rem 2rem;
  border-radius: 30px;
  font-size: 1.1rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  text-decoration: none;
  display: inline-block;
}

.cta-button:hover {
  background: var(--accent-hover);
  transform: translateY(-2px);
  box-shadow: 0 10px 20px rgba(255, 107, 107, 0.3);
}

/* Content Grid */
.content-section {
  padding: 3rem 2rem;
  max-width: 1200px;
  margin: 0 auto;
}

.section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 2rem;
}

.section-title {
  font-family: var(--font-heading);
  font-size: 2rem;
  font-weight: 600;
  color: var(--text-primary);
}

.view-all {
  color: var(--accent-color);
  text-decoration: none;
  font-weight: 500;
  transition: color 0.3s ease;
}

.view-all:hover {
  color: var(--accent-hover);
}

/* Anime Grid */
.anime-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 1.5rem;
}

.anime-card {
  background: var(--bg-secondary);
  border-radius: 12px;
  overflow: hidden;
  transition: all 0.3s ease;
  cursor: pointer;
  position: relative;
}

.anime-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 15px 30px rgba(0, 0, 0, 0.5);
}

.anime-thumbnail {
  position: relative;
  width: 100%;
  height: 300px;
  overflow: hidden;
}

.anime-thumbnail img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;
}

.anime-card:hover .anime-thumbnail img {
  transform: scale(1.1);
}

.episode-badge {
  position: absolute;
  top: 10px;
  right: 10px;
  background: var(--accent-color);
  color: white;
  padding: 0.3rem 0.8rem;
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 600;
}

.status-badge {
  position: absolute;
  top: 10px;
  left: 10px;
  background: var(--success-color);
  color: white;
  padding: 0.3rem 0.8rem;
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 600;
}

.status-badge.ongoing {
  background: var(--warning-color);
}

.anime-info {
  padding: 1rem;
}

.anime-title {
  font-size: 1rem;
  font-weight: 600;
  margin-bottom: 0.5rem;
  line-height: 1.3;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.anime-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.anime-type {
  background: var(--bg-tertiary);
  padding: 0.2rem 0.6rem;
  border-radius: 15px;
  font-size: 0.75rem;
}

/* Footer */
.footer {
  background: var(--bg-secondary);
  border-top: 1px solid var(--border-color);
  padding: 3rem 2rem 1rem;
  margin-top: 4rem;
}

.footer-content {
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 2rem;
}

.footer-section h3 {
  color: var(--accent-color);
  margin-bottom: 1rem;
  font-family: var(--font-heading);
}

.footer-links {
  list-style: none;
}

.footer-links li {
  margin-bottom: 0.5rem;
}

.footer-links a {
  color: var(--text-secondary);
  text-decoration: none;
  transition: color 0.3s ease;
}

.footer-links a:hover {
  color: var(--accent-color);
}

.footer-bottom {
  text-align: center;
  padding-top: 2rem;
  border-top: 1px solid var(--border-color);
  margin-top: 2rem;
  color: var(--text-secondary);
}

/* Responsive Design */
@media (max-width: 768px) {
  .header-container {
    padding: 1rem;
  }

  .nav-menu {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
    right: 0;
    background: var(--bg-secondary);
    flex-direction: column;
    padding: 1rem;
    border-top: 1px solid var(--border-color);
  }

  .nav-menu.active {
    display: flex;
  }

  .mobile-toggle {
    display: flex;
  }

  .search-input {
    width: 150px;
  }

  .search-input:focus {
    width: 180px;
  }

  .hero-title {
    font-size: 2.5rem;
  }

  .anime-grid {
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 1rem;
  }

  .content-section {
    padding: 2rem 1rem;
  }
}

/* NSFW Warning Modal */
.nsfw-modal {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.9);
  display: none;
  align-items: center;
  justify-content: center;
  z-index: 10000;
}

.nsfw-modal.active {
  display: flex;
}

.nsfw-content {
  background: var(--bg-secondary);
  padding: 2rem;
  border-radius: 15px;
  max-width: 500px;
  text-align: center;
  border: 2px solid var(--accent-color);
}

.nsfw-warning {
  color: var(--warning-color);
  font-size: 1.2rem;
  margin-bottom: 1rem;
}

.nsfw-buttons {
  display: flex;
  gap: 1rem;
  justify-content: center;
  margin-top: 1.5rem;
}

.btn-nsfw {
  padding: 0.8rem 1.5rem;
  border: none;
  border-radius: 25px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.btn-nsfw.proceed {
  background: var(--danger-color);
  color: white;
}

.btn-nsfw.cancel {
  background: var(--bg-tertiary);
  color: var(--text-primary);
}

.btn-nsfw:hover {
  transform: translateY(-2px);
}

/* Watermark */
.watermark-player {
  position: absolute;
  top: 10px;
  left: 10px;
  background: rgba(0, 0, 0, 0.7);
  color: white;
  padding: 0.5rem 1rem;
  border-radius: 5px;
  font-size: 0.9rem;
  z-index: 10;
}

/* Anti Copy */
.no-copy {
  -webkit-user-select: none;
  -moz-user-select: none;
  -ms-user-select: none;
  user-select: none;
}

/* Scrollbar Custom */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: var(--bg-primary);
}

::-webkit-scrollbar-thumb {
  background: var(--accent-color);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--accent-hover);
}

head.script:
// Global Variables
const SITE_CONFIG = {
  name: "",
  url: "",
  apiUrl: "/feeds/posts/default",
  nsfwKeywords: ["yaoi", "bl", "gl", "bxb", "gxg", "hentai"],
  antiCopy: true,
  watermark: true
};

// Loading Screen
window.addEventListener("load", function() {
  setTimeout(function() {
    document.getElementById("loading-screen").style.opacity = "0";
    setTimeout(function() {
      document.getElementById("loading-screen").style.display = "none";
    }, 500);
  }, 1000);
});

// Mobile Menu Toggle
function toggleMobileMenu() {
  const navMenu = document.querySelector(".nav-menu");
  navMenu.classList.toggle("active");
}

// Search Function
function performSearch(query) {
  if (query.trim() === "") return;
  window.location.href = "/search?q=" + encodeURIComponent(query);
}

// NSFW Warning
function checkNSFWContent(title) {
  const lowerTitle = title.toLowerCase();
  return SITE_CONFIG.nsfwKeywords.some(keyword => lowerTitle.includes(keyword));
}

function showNSFWWarning(title, callback) {
  const modal = document.getElementById("nsfw-modal");
  const titleElement = document.getElementById("nsfw-title");

  titleElement.textContent = title;
  modal.classList.add("active");

  window.nsfwCallback = callback;
}

function proceedNSFW() {
  document.getElementById("nsfw-modal").classList.remove("active");
  if (window.nsfwCallback) {
    window.nsfwCallback();
  }
}

function cancelNSFW() {
  document.getElementById("nsfw-modal").classList.remove("active");
}

// Anti Copy Protection
if (SITE_CONFIG.antiCopy) {
  document.addEventListener("contextmenu", function(e) {
    e.preventDefault();
  });

  document.addEventListener("selectstart", function(e) {
    e.preventDefault();
  });

  document.addEventListener("copy", function(e) {
    e.preventDefault();
  });
}

// Watermark Function
function addWatermark(containerId) {
  if (!SITE_CONFIG.watermark) return;

  const container = document.getElementById(containerId);
  if (container) {
    const watermark = document.createElement("div");
    watermark.className = "watermark-player";
    watermark.textContent = SITE_CONFIG.name;
    container.appendChild(watermark);
  }
}

// Lazy Loading for Images
function lazyLoadImages() {
  const images = document.querySelectorAll("img[data-src]");
  const imageObserver = new IntersectionObserver((entries, observer) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        const img = entry.target;
        img.src = img.dataset.src;
        img.classList.remove("lazy");
        imageObserver.unobserve(img);
      }
    });
  });

  images.forEach(img => imageObserver.observe(img));
}

// Initialize Functions
document.addEventListener("DOMContentLoaded", function() {
  lazyLoadImages();
});

body.script:
// Back to Top Button
window.onscroll = function() {
  const backToTop = document.getElementById("back-to-top");
  if (document.body.scrollTop > 100 || document.documentElement.scrollTop > 100) {
    backToTop.style.display = "block";
  } else {
    backToTop.style.display = "none";
  }
};

function scrollToTop() {
  window.scrollTo({
    top: 0,
    behavior: "smooth"
  });
}

// Search functionality
document.getElementById("search-input").addEventListener("keypress", function(e) {
  if (e.key === "Enter") {
    performSearch(this.value);
  }
});
    performSearch(this.value);
  }
});
